import{_ as t,o as i,c as a,ak as s,at as o,au as n,av as l}from"./chunks/framework.B9OfcISu.js";const y=JSON.parse('{"title":"Git / GitHub","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"tools/coding/git.md","filePath":"tools/coding/git.md"}'),r={name:"tools/coding/git.md"};function h(c,e,d,u,g,p){return i(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="git-github" tabindex="-1"><img src="'+o+'" style="display:inline-block;vertical-align:middle;height:48px;margin-right:8px;"> Git / GitHub <a class="header-anchor" href="#git-github" aria-label="Permalink to “Git / GitHub”">​</a></h1><p>Git is the engine under the hood, and GitHub is the shiny showroom where everyone sees your work. Mastering a handful of core commands will handle 90% of your daily workflow.</p><h2 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to “Installation”">​</a></h2><h3 id="arch-linux" tabindex="-1">Arch Linux <a class="header-anchor" href="#arch-linux" aria-label="Permalink to “Arch Linux”">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pacman</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -S</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> git</span></span></code></pre></div><h2 id="ssh-key" tabindex="-1">SSH Key <a class="header-anchor" href="#ssh-key" aria-label="Permalink to “SSH Key”">​</a></h2><p>You will need an SSH key so that your computer and GitHub will have a &quot;secret handshake&quot; that identifies you automatically, without needing any further authentication.</p><p><strong>1. Generate the key</strong></p><p>The following command will ask &quot;Enter file in which to save the key.&quot; Just hit Enter to accept the default location.</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh-keygen</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -t</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ed25519</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -C</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;your_email@example.com&quot;</span></span></code></pre></div><p><strong>2. Copy the Public Key</strong></p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.ssh/id_ed25519.pub</span></span></code></pre></div><p>(then manually highlight and copy the text)</p><p><strong>3. Add the Key to GitHub</strong></p><p>Login to <strong>GitHub</strong>, and go to <strong>Settings</strong>. In the left sidebar, click <strong>SSH and GPG keys</strong>. Then, click the green <strong>New SSH key</strong> button. Give it a title, paste your key and click <strong>Add SSH key</strong>.</p><p><strong>4. Test the Connection</strong></p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -T</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> git@github.com</span></span></code></pre></div><p>If you see <em>&quot;Hi [YourUsername]! You&#39;ve successfully authenticated&quot;</em>, everything is set and you are ready to go.</p><h2 id="repository-initialization" tabindex="-1">Repository Initialization <a class="header-anchor" href="#repository-initialization" aria-label="Permalink to “Repository Initialization”">​</a></h2><ul><li><code>git clone &lt;URL&gt;</code>: Download an existing GitHub repository to your computer</li></ul><p><img src="'+n+'" alt="Git URL"> You can get the required URL pushing the green &quot;Code&quot; button and copying the SSH URL.</p><ul><li><code>git init</code>: Git initialization in current folder</li><li><code>git remote add origin &lt;URL&gt;</code>: Connect the local repository to the GitHub one</li></ul><h2 id="core-workflow" tabindex="-1">Core Workflow <a class="header-anchor" href="#core-workflow" aria-label="Permalink to “Core Workflow”">​</a></h2><p>Think of Git as a three-stage process for saving your work. You move files from your folder to a &quot;staging area&quot; before finally sealing them into the permanent history (the repository).</p><ul><li><code>git add &lt;file&gt;</code>: Move changes to the Staging Area. Use <code>git add .</code> to stage everything instead.</li><li><code>git commit -m &quot;Your message&quot;</code>: Record the staged changes permanently. Remember, keep messages descriptive (e.g., &quot;Fix login button styling&quot;).</li></ul><p>However, you would normally like to work on your, personal branch, unless stated otherwise. Branches allow you to work on new features without breaking the &quot;Main&quot; (stable) version of the project.</p><ul><li><code>git checkout -b &lt;branch_name&gt;</code>: Create and switch to a new branch.</li></ul><p><img src="'+l+'" alt="Branch check"> In VSCode, you can monitor the branch you&#39;re working in by looking at the bottom left of the screen.</p><ul><li><code>git status</code>: A very helpful command you can always run to check files status and the current branch.</li></ul><h2 id="pushing-to-github" tabindex="-1">Pushing to GitHub <a class="header-anchor" href="#pushing-to-github" aria-label="Permalink to “Pushing to GitHub”">​</a></h2><p>To share your code, you need to link your local folder to the remote repository on GitHub.</p><ul><li><code>git push -u origin main</code>: Send your local commits to GitHub. The <code>-u</code> flag remembers your preferences for next time.</li><li><code>git pull</code>: Grab the latest changes from GitHub and merge them into your local files. Use this often to stay up to date with workmates. Alternatively, you can use <code>git fetch</code> and then <code>git merge</code> to have a safe peek at the changes before merging in.</li></ul><h2 id="pull-requests" tabindex="-1">Pull Requests <a class="header-anchor" href="#pull-requests" aria-label="Permalink to “Pull Requests”">​</a></h2><p>A <strong>Pull Request</strong> (PR) isn&#39;t a Git command; it’s a GitHub feature. It’s a formal request to merge your branch into the main project and you can do it by going to the GitHub repository page. It allows for:</p><ul><li>Code Review: Others can comment on specific lines.</li><li>Testing: Automated tools can check if your code breaks anything.</li><li>Discussion: A place to talk about why the changes were made.</li></ul>',35)])])}const b=t(r,[["render",h]]);export{y as __pageData,b as default};
